#include<bits/stdc++.h>
using namespace std;

const int MX = 1e9;

int main() {
    int n; 
    cin >> n;

    int a[n];
    for(int i = 0; i < n; i++) {
        cin >> a[i];
    }

    map<int,int> mp;

    int count = 0;
    for(int i = 0; i < n; i++) {
        // If a[i] * a[i] exceeds the max, discard it
        if((a[i] * 1ll * a[i]) < MX) { 
            count += mp[a[i] * a[i]];
        }
        mp[a[i]]++;
    }

    cout << count;

    return 0;
}

